namespace sv_a61ce4d1ff064bb8b559e4ca90b6f4d0.Services;

public enum Theme
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service that holds per-circuit theme state.
/// Components subscribe to OnChange to react to theme updates.
/// </summary>
public class ThemeService
{
    private Theme _theme = Theme.Light;
    private string _accentColor = "#1b6ec2";

    public Theme Theme
    {
        get => _theme;
        set
        {
            if (_theme == value) return;
            _theme = value;
            NotifyChanged();
        }
    }

    public string AccentColor
    {
        get => _accentColor;
        set
        {
            if (_accentColor == value) return;
            _accentColor = value;
            NotifyChanged();
        }
    }

    public event Action? OnChange;

    private void NotifyChanged() => OnChange?.Invoke();
}

@*
    This component MUST be rendered with @rendermode InteractiveServer.
    It lives in the layout and bridges the static/interactive boundary
    by pushing theme state to the DOM via JS interop.
*@
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService
@inject IJSRuntime JS

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += OnThemeChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await ApplyThemeToDOM();
        }
    }

    private async void OnThemeChanged()
    {
        await InvokeAsync(async () =>
        {
            await ApplyThemeToDOM();
            StateHasChanged();
        });
    }

    private async Task ApplyThemeToDOM()
    {
        var themeName = ThemeService.Theme.ToString().ToLowerInvariant();
        await JS.InvokeVoidAsync("themeInterop.applyTheme", themeName, ThemeService.AccentColor);
    }

    public void Dispose()
    {
        ThemeService.OnChange -= OnThemeChanged;
    }
}

@implements IDisposable
@inject ThemeService ThemeService

<div class="theme-toggle">
    <span class="theme-indicator" title="Current theme: @ThemeService.Theme">
        @GetThemeIcon()
    </span>
    <button class="btn btn-sm btn-outline-secondary" @onclick="CycleTheme" title="Toggle theme">
        Switch Theme
    </button>
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += OnThemeChanged;
    }

    private void CycleTheme()
    {
        ThemeService.Theme = ThemeService.Theme switch
        {
            Theme.Light => Theme.Dark,
            Theme.Dark => Theme.System,
            Theme.System => Theme.Light,
            _ => Theme.Light
        };
    }

    private string GetThemeIcon() => ThemeService.Theme switch
    {
        Theme.Light => "☀️",
        Theme.Dark => "🌙",
        Theme.System => "💻",
        _ => "☀️"
    };

    private void OnThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnChange -= OnThemeChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-3" style="max-width: 500px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>
        <div class="btn-group mb-3" role="group">
            @foreach (var theme in Enum.GetValues<Theme>())
            {
                <button class="btn @(ThemeService.Theme == theme ? "btn-primary" : "btn-outline-primary")"
                        @onclick="() => SetTheme(theme)">
                    @theme
                </button>
            }
        </div>

        <h5 class="card-title">Accent Color</h5>
        <div class="d-flex align-items-center gap-3 mb-3">
            <input type="color" class="form-control form-control-color"
                   value="@ThemeService.AccentColor"
                   @onchange="OnAccentColorChanged"
                   title="Choose accent color" />
            <span>@ThemeService.AccentColor</span>
        </div>

        <div class="mt-3 p-3 border rounded">
            <strong>Preview:</strong>
            <span style="color: @ThemeService.AccentColor;">
                This text uses your accent color.
            </span>
        </div>
    </div>
</div>

@code {
    protected override void OnInitialized()
    {
        ThemeService.OnChange += OnThemeChanged;
    }

    private void SetTheme(Theme theme)
    {
        ThemeService.Theme = theme;
    }

    private void OnAccentColorChanged(ChangeEventArgs e)
    {
        ThemeService.AccentColor = e.Value?.ToString() ?? "#1b6ec2";
    }

    private void OnThemeChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        ThemeService.OnChange -= OnThemeChanged;
    }
}

window.themeInterop = {
    applyTheme: function (theme, accentColor) {
        const html = document.documentElement;
        html.setAttribute('data-theme', theme);
        html.style.setProperty('--accent-color', accentColor);
    }
};

