public enum Theme
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service that holds per-circuit theme state.
/// Components subscribe to OnChange to react to theme updates.
/// </summary>
public class ThemeService
{
    private Theme _theme = Theme.Light;
    private string _accentColor = "#1b6ec2";

    public Theme Theme
    {
        get => _theme;
        set
        {
            if (_theme == value) return;
            _theme = value;
            NotifyChanged();
        }
    }

    public string AccentColor
    {
        get => _accentColor;
        set
        {
            if (_accentColor == value) return;
            _accentColor = value;
            NotifyChanged();
        }
    }

    public event Action? OnChange;

    private void NotifyChanged() => OnChange?.Invoke();
}

