html, body {
    font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif;
}

/* Theme CSS custom properties */
:root,
[data-theme="light"] {
    --bg-color: #ffffff;
    --text-color: #212529;
    --accent-color: #1b6ec2;
    --surface-color: #f7f7f7;
    --border-color: #d6d5d5;
    color-scheme: light;
}

[data-theme="dark"] {
    --bg-color: #1a1a2e;
    --text-color: #e0e0e0;
    --surface-color: #16213e;
    --border-color: #444;
    color-scheme: dark;
}

[data-theme="system"] {
    color-scheme: light dark;
}

@media (prefers-color-scheme: dark) {
    [data-theme="system"] {
        --bg-color: #1a1a2e;
        --text-color: #e0e0e0;
        --surface-color: #16213e;
        --border-color: #444;
    }
}

body {
    background-color: var(--bg-color);
    color: var(--text-color);
    transition: background-color 0.3s, color 0.3s;
}

a, .btn-link {
    color: var(--accent-color);
}

